import{_ as e,o as a,c as t,a2 as o}from"./chunks/framework.D14Z5eOz.js";const u=JSON.parse('{"title":"CI/CD","description":"","frontmatter":{},"headers":[],"relativePath":"maintainers/ci-cd.md","filePath":"maintainers/ci-cd.md","lastUpdated":1784865624000}'),i={name:"maintainers/ci-cd.md"};function n(l,s,r,d,p,c){return a(),t("div",null,[...s[0]||(s[0]=[o(`<h1 id="ci-cd" tabindex="-1">CI/CD <a class="header-anchor" href="#ci-cd" aria-label="Permalink to &quot;CI/CD&quot;">​</a></h1><p>GitHub Actions pipelines for continuous integration and <strong>automatic releases on push to <code>main</code></strong>.</p><h2 id="runtime" tabindex="-1">Runtime <a class="header-anchor" href="#runtime" aria-label="Permalink to &quot;Runtime&quot;">​</a></h2><ul><li><strong>Node.js 24</strong> everywhere: app <code>engines</code> (<code>&gt;=24</code>), local develop, and GitHub Actions</li><li>Actions: <code>actions/setup-node@v5</code>, <code>actions/checkout@v5</code>, <code>upload-artifact@v5</code>, <code>softprops/action-gh-release@v3</code> (Node 24 runtimes)</li><li><strong>pnpm</strong>: <code>pnpm/action-setup@v4</code> <strong>before</strong> <code>setup-node</code>, with <code>package-manager-cache: false</code><br> (<code>setup-node@v5</code> otherwise looks for <code>pnpm</code> too early and fails with “Unable to locate executable file: pnpm”)</li></ul><h2 id="local-pre-commit-husky" tabindex="-1">Local pre-commit (husky) <a class="header-anchor" href="#local-pre-commit-husky" aria-label="Permalink to &quot;Local pre-commit (husky)&quot;">​</a></h2><p>After <code>pnpm install</code>, a <strong>pre-commit</strong> hook runs <code>pnpm typecheck</code> so unused imports / TS errors fail before push (same gate as CI typecheck). Config lives in repo root <code>.husky/pre-commit</code>. Skip once with <code>git commit --no-verify</code> or <code>HUSKY=0</code>.</p><h2 id="workflows" tabindex="-1">Workflows <a class="header-anchor" href="#workflows" aria-label="Permalink to &quot;Workflows&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Workflow</th><th>File (repo root)</th><th>When</th><th>What</th></tr></thead><tbody><tr><td><strong>CI</strong></td><td><code>.github/workflows/ci.yml</code></td><td>PR / push to <code>main</code></td><td>Build, test, typecheck, CLI smoke, npm pack dry-run</td></tr><tr><td><strong>Docs site</strong></td><td><code>.github/workflows/docs.yml</code></td><td>Push to <code>main</code> affecting <code>docs/**</code></td><td>VitePress → GitHub Pages</td></tr><tr><td><strong>Auto release on push</strong></td><td><code>.github/workflows/release-on-push.yml</code></td><td>Push to <code>main</code> (package changes)</td><td><strong>Auto version bump</strong> → test → <strong>npm publish</strong> → tag → GitHub Release</td></tr><tr><td><strong>Release (manual)</strong></td><td><code>.github/workflows/release.yml</code></td><td>Manual / classic GitHub Release event</td><td>Optional path if you still create releases by hand</td></tr></tbody></table><h2 id="automatic-version-bump-on-push-default" tabindex="-1">Automatic version bump on push (default) <a class="header-anchor" href="#automatic-version-bump-on-push-default" aria-label="Permalink to &quot;Automatic version bump on push (default)&quot;">​</a></h2><p>You do <strong>not</strong> need to bump versions manually for normal releases.</p><h3 id="flow" tabindex="-1">Flow <a class="header-anchor" href="#flow" aria-label="Permalink to &quot;Flow&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>push to main (packages/** changed)</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>  skip if commit is chore(release): … or [skip release]</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>  detect bump from conventional commits since last git tag</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>  bump package.json versions (root, core, cli) together</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>  build + test + CLI smoke</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>  npm publish @structured-vibe-coding/core + @structured-vibe-coding/cli</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>  commit chore(release): vX.Y.Z [skip release]</span></span>
<span class="line"><span>  tag vX.Y.Z + push</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>  GitHub Release</span></span></code></pre></div><h3 id="how-the-bump-type-is-chosen" tabindex="-1">How the bump type is chosen <a class="header-anchor" href="#how-the-bump-type-is-chosen" aria-label="Permalink to &quot;How the bump type is chosen&quot;">​</a></h3><p>From commit subjects <strong>since the last git tag</strong>:</p><table tabindex="0"><thead><tr><th>Commits contain</th><th>Bump</th></tr></thead><tbody><tr><td><code>BREAKING CHANGE</code> or <code>feat!:</code> / <code>fix!:</code></td><td><strong>major</strong></td></tr><tr><td><code>feat:</code> / <code>feat(scope):</code></td><td><strong>minor</strong></td></tr><tr><td>anything else (fix, chore, docs, …)</td><td><strong>patch</strong></td></tr></tbody></table><p>Examples:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> commit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;fix: skip stage navigation&quot;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># → 0.1.0 → 0.1.1</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> commit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;feat: add agent handoff panel&quot;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># → 0.1.1 → 0.2.0</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> commit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;feat!: redesign workflow schema&quot;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># → 0.2.0 → 1.0.0</span></span></code></pre></div><h3 id="skip-a-release" tabindex="-1">Skip a release <a class="header-anchor" href="#skip-a-release" aria-label="Permalink to &quot;Skip a release&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> commit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;docs: fix typo [skip release]&quot;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># or after an automated release (already skipped):</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># chore(release): v0.1.1 [skip release]</span></span></code></pre></div><p>Pushes that only touch docs outside <code>packages/**</code> also skip the auto-release path filter.</p><h3 id="manual-bump-type" tabindex="-1">Manual bump type <a class="header-anchor" href="#manual-bump-type" aria-label="Permalink to &quot;Manual bump type&quot;">​</a></h3><p><strong>Actions → Auto release on push → Run workflow</strong></p><ul><li><code>bump</code>: <code>auto</code> | <code>patch</code> | <code>minor</code> | <code>major</code></li><li><code>dry_run</code>: build + bump locally in the job only (no npm, no git push)</li></ul><h3 id="there-are-no-new-packages-that-should-be-published" tabindex="-1">“There are no new packages that should be published” <a class="header-anchor" href="#there-are-no-new-packages-that-should-be-published" aria-label="Permalink to &quot;“There are no new packages that should be published”&quot;">​</a></h3><p>That means the <strong>current version is already on npm</strong> (e.g. <code>0.2.0</code>). npm does not allow re-publishing the same version.</p><p>Workflows now:</p><ol><li>Detect if <code>@structured-vibe-coding/core</code> / <code>cli</code> already have this version</li><li><strong>Auto patch-bump</strong> (<code>0.2.0</code> → <code>0.2.1</code> …) until free</li><li>Publish and <strong>fail</strong> if pnpm still skips</li></ol><p><strong>Release (CD)</strong> manual run also has input <strong><code>bump</code></strong>: <code>none</code> | <code>patch</code> | <code>minor</code> | <code>major</code>.</p><h3 id="local-version-scripts" tabindex="-1">Local version scripts <a class="header-anchor" href="#local-version-scripts" aria-label="Permalink to &quot;Local version scripts&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> version:bump</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # auto from commits since last tag</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> version:patch</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> version:minor</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> version:major</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/bump-version.mjs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --set</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1.0.0</span></span></code></pre></div><hr><h2 id="one-time-setup" tabindex="-1">One-time setup <a class="header-anchor" href="#one-time-setup" aria-label="Permalink to &quot;One-time setup&quot;">​</a></h2><ol><li><p><strong>npm scope</strong><br> Packages are <code>@structured-vibe-coding/core</code> and <code>@structured-vibe-coding/cli</code>. Own that org/scope on npm, or rename packages.</p></li><li><p><strong>Secret <code>NPM_TOKEN</code></strong> (you already added this)</p><ul><li>Automation or granular token with <strong>publish</strong> + <strong>bypass 2FA</strong></li><li>Repo → Settings → Secrets and variables → Actions → <code>NPM_TOKEN</code></li></ul></li><li><p><strong>Workflow permissions</strong><br> Repo → Settings → Actions → General → <strong>Workflow permissions</strong>:</p><ul><li>Allow <strong>Read and write</strong> permissions (so the bot can push the release commit + tags)</li></ul></li><li><p><strong>First publish</strong><br> Push a change under <code>packages/</code> to <code>main</code>, or run <strong>Auto release on push</strong> manually.<br> First run will tag <code>v0.1.1</code> (patch from <code>0.1.0</code>) unless commits since start include <code>feat:</code>.</p></li></ol><hr><h2 id="docs-site-github-pages" tabindex="-1">Docs site (GitHub Pages) <a class="header-anchor" href="#docs-site-github-pages" aria-label="Permalink to &quot;Docs site (GitHub Pages)&quot;">​</a></h2><p>Public site: <code>https://harsha09.github.io/spec-driven-development/</code></p><p><strong>Pages setting:</strong> Deploy from branch <strong><code>gh-pages</code></strong> / <strong><code>/</code> (root)</strong>.<br> Do <strong>not</strong> use <code>main</code> + <code>/docs</code> (raw Markdown via Jekyll — broken nav and theme).</p><p>Workflow <code>.github/workflows/docs.yml</code> builds VitePress and publishes to <strong><code>gh-pages</code></strong>.</p><p>Local: <code>pnpm docs:dev</code> · <code>pnpm docs:build</code></p><h2 id="ci-every-pr" tabindex="-1">CI (every PR) <a class="header-anchor" href="#ci-every-pr" aria-label="Permalink to &quot;CI (every PR)&quot;">​</a></h2><p>No secrets. Quality gate only (build, typecheck, test, CLI smoke, npm pack dry-run). Does <strong>not</strong> publish npm.</p><hr><h2 id="install-after-a-successful-auto-release" tabindex="-1">Install after a successful auto-release <a class="header-anchor" href="#install-after-a-successful-auto-release" aria-label="Permalink to &quot;Install after a successful auto-release&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @structured-vibe-coding/cli</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sdd</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --help</span></span></code></pre></div><hr><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Issue</th><th>Fix</th></tr></thead><tbody><tr><td>No auto release on push</td><td>Path must include <code>packages/**</code>; message must not be <code>chore(release):</code> or <code>[skip release]</code></td></tr><tr><td>Cannot push release commit</td><td>Enable <strong>Read and write</strong> workflow permissions</td></tr><tr><td><code>403</code> npm publish</td><td>Token needs publish + bypass 2FA; confirm <code>@structured-vibe-coding</code> ownership</td></tr><tr><td>Version already on npm</td><td>Bump already published; wait for next commit or <code>workflow_dispatch</code> with higher bump</td></tr><tr><td>Loop of releases</td><td>Release commits include <code>[skip release]</code> / <code>chore(release):</code> and are ignored</td></tr></tbody></table><hr><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="../scripts/bump-version.mjs"><code>scripts/bump-version.mjs</code></a> — shared bump logic</li><li>Classic manual release workflow still available if you prefer tags-only releases</li></ul>`,50)])])}const g=e(i,[["render",n]]);export{u as __pageData,g as default};
